import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate, useParams } from 'react-router-dom';

const ResetPassword = () => {
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();
    const { token } = useParams();

    const handleResetPassword = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setMessage('');

        if (!newPassword || !confirmPassword) {
            setError('Please fill in all fields'); setLoading(false); return;
        }
        if (newPassword.length < 6) {
            setError('Password must be at least 6 characters long'); setLoading(false); return;
        }
        if (newPassword !== confirmPassword) {
            setError('Passwords do not match'); setLoading(false); return;
        }

        try {
            const { data } = await API.post('/auth/reset-password', { token, newPassword });
            setMessage(data.message || 'Password reset successfully!');
            setNewPassword(''); setConfirmPassword('');
            setTimeout(() => navigate('/'), 2000);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to reset password. Please try again.');
        } finally { setLoading(false); }
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="login-brand">
                    <div className="login-brand-icon">🔐</div>
                    <h1 className="login-title">Reset Password</h1>
                    <p className="login-subtitle">Create a new secure password</p>
                </div>

                {error && <div className="login-error">⚠️ {error}</div>}
                {message && <div className="alert alert-success">{message}</div>}

                <form onSubmit={handleResetPassword}>
                    <div className="login-form-group">
                        <input type="password" className="login-input" placeholder=" "
                            value={newPassword} onChange={e => setNewPassword(e.target.value)} required />
                        <label className="login-label">New Password</label>
                    </div>
                    <div className="login-form-group">
                        <input type="password" className="login-input" placeholder=" "
                            value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required />
                        <label className="login-label">Confirm Password</label>
                    </div>
                    <button type="submit" className="btn-login" disabled={loading}>
                        {loading ? 'Resetting...' : 'Reset Password'}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default ResetPassword;
